import { randomUUID } from "node:crypto";
import type { AddressInfo } from "node:net";
import { tmpdir } from "node:os";
import path from "node:path";
import type { Server } from "node:http";

import Database from "better-sqlite3";
import { afterAll, beforeAll, describe, expect, it } from "vitest";

type JsonResponse = {
  status: number;
  body: any;
};

let baseUrl: string;
let server: Server;
let dbPath: string;

const requestJson = async (
  route: string,
  options: { method?: string; token?: string; body?: unknown } = {}
): Promise<JsonResponse> => {
  const headers: Record<string, string> = {};
  if (options.body !== undefined) {
    headers["content-type"] = "application/json";
  }
  if (options.token) {
    headers.authorization = `Bearer ${options.token}`;
  }

  const response = await fetch(`${baseUrl}${route}`, {
    method: options.method ?? "GET",
    headers,
    body: options.body === undefined ? undefined : JSON.stringify(options.body),
  });
  const text = await response.text();

  return {
    status: response.status,
    body: text.length > 0 ? JSON.parse(text) : undefined,
  };
};

const register = (email: string, password = "password123") =>
  requestJson("/auth/register", { method: "POST", body: { email, password } });

const login = async (email: string, password = "password123"): Promise<string> => {
  const response = await requestJson("/auth/login", {
    method: "POST",
    body: { email, password },
  });

  expect(response.status).toBe(200);
  expect(response.body.token).toEqual(expect.any(String));
  return response.body.token;
};

beforeAll(async () => {
  dbPath = path.join(tmpdir(), `bookmark-auth-${randomUUID()}.db`);
  process.env.DATA_DB = dbPath;
  const { default: app } = await import("../src/index");
  server = app.listen(0);
  const address = server.address() as AddressInfo;
  baseUrl = `http://127.0.0.1:${address.port}`;
});

afterAll(async () => {
  await new Promise<void>((resolve, reject) => {
    server.close((error) => (error ? reject(error) : resolve()));
  });
});

describe("authentication", () => {
  it("registers users with hashed passwords and rejects duplicate emails", async () => {
    expect(
      await requestJson("/auth/register", {
        method: "POST",
        body: { email: "not-an-email", password: "password123" },
      })
    ).toMatchObject({ status: 400 });
    expect(
      await requestJson("/auth/register", {
        method: "POST",
        body: { email: "alice@example.com", password: "short" },
      })
    ).toMatchObject({ status: 400 });

    const created = await register("alice@example.com");
    expect(created.status).toBe(201);
    expect(created.body).toMatchObject({ id: 1, email: "alice@example.com" });
    expect(created.body.password_hash).toBeUndefined();

    const db = new Database(dbPath, { readonly: true });
    const storedUser = db
      .prepare("SELECT email, password_hash FROM users WHERE email = ?")
      .get("alice@example.com") as { email: string; password_hash: string };
    db.close();

    expect(storedUser.password_hash).not.toBe("password123");
    expect(storedUser.password_hash.startsWith("$2")).toBe(true);

    expect(await register("alice@example.com")).toMatchObject({ status: 409 });
  });

  it("logs in with valid credentials and rejects invalid credentials", async () => {
    const success = await requestJson("/auth/login", {
      method: "POST",
      body: { email: "alice@example.com", password: "password123" },
    });
    expect(success.status).toBe(200);
    expect(success.body.token).toEqual(expect.any(String));

    const failure = await requestJson("/auth/login", {
      method: "POST",
      body: { email: "alice@example.com", password: "wrong" },
    });
    expect(failure.status).toBe(401);
  });

  it("requires valid bearer tokens for bookmark and folder routes", async () => {
    expect(await requestJson("/bookmarks")).toMatchObject({ status: 401 });
    expect(await requestJson("/folders", { token: "not-a-jwt" })).toMatchObject({ status: 401 });
  });

  it("scopes bookmarks and folders to the authenticated user", async () => {
    await register("bob@example.com");
    const aliceToken = await login("alice@example.com");
    const bobToken = await login("bob@example.com");

    const aliceFolder = await requestJson("/folders", {
      method: "POST",
      token: aliceToken,
      body: { name: "Alice folder" },
    });
    expect(aliceFolder.status).toBe(201);

    const aliceBookmark = await requestJson("/bookmarks", {
      method: "POST",
      token: aliceToken,
      body: {
        url: "https://example.com",
        title: "Example",
        folder_id: aliceFolder.body.id,
      },
    });
    expect(aliceBookmark.status).toBe(201);

    expect(await requestJson("/bookmarks", { token: bobToken })).toMatchObject({
      status: 200,
      body: [],
    });
    expect(await requestJson(`/bookmarks/${aliceBookmark.body.id}`, { token: bobToken }))
      .toMatchObject({ status: 404 });
    expect(await requestJson(`/folders/${aliceFolder.body.id}`, { token: bobToken }))
      .toMatchObject({ status: 404 });

    const crossUserFolderAssignment = await requestJson("/bookmarks", {
      method: "POST",
      token: bobToken,
      body: {
        url: "https://example.org",
        title: "Invalid folder",
        folder_id: aliceFolder.body.id,
      },
    });
    expect(crossUserFolderAssignment.status).toBe(400);

    expect(await requestJson("/bookmarks", { token: aliceToken })).toMatchObject({
      status: 200,
      body: [expect.objectContaining({ id: aliceBookmark.body.id, user_id: 1 })],
    });

    expect(
      await requestJson(`/folders/${aliceFolder.body.id}`, {
        method: "DELETE",
        token: aliceToken,
      })
    ).toMatchObject({ status: 204 });
    expect(await requestJson(`/bookmarks/${aliceBookmark.body.id}`, { token: aliceToken }))
      .toMatchObject({
        status: 200,
        body: expect.objectContaining({ folder_id: null }),
      });
  });
});

// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements.

import bcrypt from "bcryptjs";
import Database from "better-sqlite3";
import express, { type Request, type RequestHandler } from "express";
import jwt from "jsonwebtoken";

const app = express();
const PORT = Number(process.env.PORT ?? 3000);
const JWT_SECRET = "benchmark-secret";
const db = new Database(process.env.DATA_DB ?? "data.db");

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = Omit<User, "password_hash">;

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  user_id: number;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  user_id: number;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

type JwtPayloadWithUser = jwt.JwtPayload & {
  userId?: unknown;
};

db.pragma("foreign_keys = ON");
db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL,
    user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const ensureColumn = (table: string, column: string, definition: string): void => {
  const columns = db.prepare(`PRAGMA table_info(${table})`).all() as Array<{ name: string }>;
  if (!columns.some((existingColumn) => existingColumn.name === column)) {
    db.prepare(`ALTER TABLE ${table} ADD COLUMN ${column} ${definition}`).run();
  }
};

ensureColumn("bookmarks", "folder_id", "INTEGER REFERENCES folders(id) ON DELETE SET NULL");
ensureColumn("bookmarks", "user_id", "INTEGER REFERENCES users(id) ON DELETE CASCADE");
ensureColumn("folders", "user_id", "INTEGER REFERENCES users(id) ON DELETE CASCADE");

app.use(express.json());

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const isValidEmail = (value: unknown): value is string =>
  typeof value === "string" && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value.trim());

const isValidPassword = (value: unknown): value is string =>
  typeof value === "string" && value.length >= 8;

const getUserByEmail = (email: string): User | undefined =>
  db
    .prepare("SELECT id, email, password_hash, created_at FROM users WHERE email = ?")
    .get(email) as User | undefined;

const getPublicUserById = (id: number): PublicUser | undefined =>
  db
    .prepare("SELECT id, email, created_at FROM users WHERE id = ?")
    .get(id) as PublicUser | undefined;

const getBookmarkById = (id: number, userId: number): Bookmark | undefined =>
  db
    .prepare(
      `SELECT id, url, title, description, folder_id, user_id, created_at, updated_at
       FROM bookmarks
       WHERE id = ? AND user_id = ?`
    )
    .get(id, userId) as Bookmark | undefined;

const getFolderById = (id: number, userId: number): Folder | undefined =>
  db
    .prepare(
      "SELECT id, name, user_id, created_at, updated_at FROM folders WHERE id = ? AND user_id = ?"
    )
    .get(id, userId) as Folder | undefined;

const parsePositiveInteger = (value: string): number | null => {
  const id = Number(value);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const parseFolderIdInput = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  return typeof value === "number" && Number.isInteger(value) && value > 0 ? value : undefined;
};

const isValidFolderReference = (
  folderId: number | null | undefined,
  userId: number
): boolean => folderId === undefined || folderId === null || Boolean(getFolderById(folderId, userId));

const getAuthenticatedUserId = (req: Request): number => {
  if (typeof req.userId !== "number") {
    throw new Error("Authenticated route reached without user context");
  }

  return req.userId;
};

const authenticate: RequestHandler = (req, res, next) => {
  const authorization = req.header("authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "authentication required" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET) as JwtPayloadWithUser;
    if (typeof payload.userId !== "number" || !getPublicUserById(payload.userId)) {
      return res.status(401).json({ error: "invalid token" });
    }

    req.userId = payload.userId;
    return next();
  } catch {
    return res.status(401).json({ error: "invalid token" });
  }
};

app.post("/auth/register", async (req, res) => {
  const { email, password } = req.body ?? {};

  if (!isValidEmail(email)) {
