app.get("/folders/:id", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id, userId);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const bookmarks = db
    .prepare(
      `SELECT id, url, title, description, folder_id, user_id, created_at, updated_at
       FROM bookmarks
       WHERE folder_id = ? AND user_id = ?
       ORDER BY id`
    )
    .all(id, userId) as Bookmark[];

  const folderWithBookmarks: FolderWithBookmarks = { ...folder, bookmarks };
  return res.status(200).json(folderWithBookmarks);
});

app.put("/folders/:id", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id, userId);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body ?? {};
  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name is required" });
  }

  db.prepare("UPDATE folders SET name = ?, updated_at = ? WHERE id = ? AND user_id = ?").run(
    name.trim(),
    new Date().toISOString(),
    id,
    userId
  );

  return res.status(200).json(getFolderById(id, userId));
});

app.delete("/folders/:id", (req, res) => {
  const userId = getAuthenticatedUserId(req);
  const id = parsePositiveInteger(req.params.id);
  const folder = id === null ? undefined : getFolderById(id, userId);

  if (id === null || !folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const transaction = db.transaction((folderId: number, ownerId: number) => {
    db.prepare(
      "UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE folder_id = ? AND user_id = ?"
    ).run(new Date().toISOString(), folderId, ownerId);
    db.prepare("DELETE FROM folders WHERE id = ? AND user_id = ?").run(folderId, ownerId);
  });

  transaction(id, userId);
  return res.status(204).send();
});

